function dailyTemperatures(temperatures: number[]): number[] {
  const out = new Array(temperatures.length).fill(0);
  const st: number[] = [];
  for (let i = 0; i < temperatures.length; i++) {
    while (st.length && temperatures[st[st.length - 1]] < temperatures[i]) {
      const j = st.pop()!;
      out[j] = i - j;
    }
    st.push(i);
  }
  return out;
}
